t.script:
(function() {
    var instanceId = ;
    var currentState = '';
    var hadPending = ;
    var interval = setInterval(function() {
        fetch('/my/instances/' + instanceId + '/status', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: {}})
        })
        .then(function(r) { return r.json(); })
        .then(function(data) {
            var result = data.result || {};
            // Reload if state changed or pending upgrade was applied
            if (result.state !== currentState || (hadPending && !result.pending_plan_id)) {
                clearInterval(interval);
                location.reload();
            }
        })
        .catch(function() {});
    }, 3000);
})();

(function() {
    var btn = document.getElementById('btn-refresh-usage');
    if (!btn) return;
    btn.addEventListener('click', function() {
        var instanceId = btn.getAttribute('data-instance-id');
        var icon = btn.querySelector('i');
        btn.disabled = true;
        icon.classList.add('fa-spin');

        fetch('/my/instances/' + instanceId + '/refresh-usage', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: {}})
        })
        .then(function(r) { return r.json(); })
        .then(function(data) {
            var r = data.result || {};
            if (r.error) return;

            function barColor(pct) {
                if (pct >= 90) return 'bg-danger';
                if (pct >= 70) return 'bg-warning';
                return 'bg-success';
            }
            function updateBar(barId, textId, text, pct) {
                var bar = document.getElementById(barId);
                var txt = document.getElementById(textId);
                if (txt) txt.textContent = text;
                if (bar) {
                    bar.style.width = Math.min(pct, 100) + '%';
                    bar.className = 'progress-bar ' + barColor(pct);
                }
            }

            updateBar('usage-cpu-bar', 'usage-cpu-text', r.cpu_usage, r.cpu_pct);
            updateBar('usage-ram-bar', 'usage-ram-text', r.ram_percent, r.ram_pct);

            var storageText = r.total_storage + ' of ' + r.storage_limit + ' GB';
            updateBar('usage-storage-bar', 'usage-storage-text', storageText, r.storage_pct);
        })
        .catch(function() {})
        .finally(function() {
            btn.disabled = false;
            icon.classList.remove('fa-spin');
        });
    });
})();
